/* ── HELPERS ── */
const genId    = () => Date.now().toString(36)+Math.random().toString(36).slice(2,6);
const genCode  = () => Math.floor(100000+Math.random()*900000).toString();
const padZ     = n  => n.toString().padStart(2,"0");
const dateKey  = (y,m,d) => `${y}-${padZ(m)}-${padZ(d)}`;
const fmtDate  = (y,m,d) => `${padZ(d)} ${MONTHS_ES[m]} ${y}`;
const getDays  = (y,m)   => new Date(y,m+1,0).getDate();
const getFirst = (y,m)   => new Date(y,m,1).getDay();
const isInPast = (y,m,d) => { const t=new Date(); t.setHours(0,0,0,0); return new Date(y,m,d)<t; };

const initAvail = () => {
  const a={}; const n=new Date();
  PASTORS.forEach(p=>{
    a[p.id]={};
    for(let d=1;d<=getDays(n.getFullYear(),n.getMonth());d++){
      const dow=new Date(n.getFullYear(),n.getMonth(),d).getDay();
      if(dow===2||dow===4)
        a[p.id][dateKey(n.getFullYear(),n.getMonth(),d)]=["10:00","11:00","16:00","17:00"];
    }
  });
  return a;
};

