/* ── TOAST ── */
function useToast() {
  const [toasts,setToasts]=useState([]);
  const show=(msg,type="success")=>{
    const id=genId();
    setToasts(t=>[...t,{id,msg,type}]);
    setTimeout(()=>setToasts(t=>t.filter(x=>x.id!==id)),3000);
  };
  return {toasts,show};
}
function Toast({toasts}) {
  return (
    <div style={{position:"fixed",top:16,left:"50%",transform:"translateX(-50%)",zIndex:9999,display:"flex",flexDirection:"column",gap:8,width:"90%",maxWidth:390,pointerEvents:"none"}}>
      {toasts.map(t=>(
        <div key={t.id} style={{background:t.type==="success"?C.green:t.type==="error"?C.red:C.blue,color:C.white,borderRadius:13,padding:"12px 16px",fontSize:14,fontWeight:600,boxShadow:"0 4px 20px rgba(0,0,0,.15)",display:"flex",alignItems:"center",gap:8}}>
          <span style={{fontSize:18}}>{t.type==="success"?"✅":t.type==="error"?"❌":"ℹ️"}</span>{t.msg}
        </div>
      ))}
    </div>
  );
}

