// ── Función para enviar correos de confirmación vía EmailJS ──────────
const EMAILJS_SERVICE_ID  = "g2951801@gmail.com"; // Service ID de EmailJS
const EMAILJS_TEMPLATE_ID = "template_qs1eite";
const EMAILJS_PUBLIC_KEY  = "d22dsgnRJb6v-fxbV";

async function sendViaEmailJS({ to_email, to_name, subject, message }) {
  const res = await fetch("https://api.emailjs.com/api/v1.0/email/send", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      service_id: EMAILJS_SERVICE_ID,
      template_id: EMAILJS_TEMPLATE_ID,
      user_id: EMAILJS_PUBLIC_KEY,
      template_params: { to_email, to_name, subject, message },
    }),
  });
  const text = await res.text();
  return { ok: res.ok, status: res.status, text };
}

async function sendConfirmationEmails({ userName, userEmail, userPhone, pastorName, pastorEmail, date, time, motiveLabel, action }) {
  const subjectMember = `${action==="confirmada"?"✅ Cita confirmada":"📝 Cita modificada"} — ${date} a las ${time}`;
  const messageMember = `Tu cita ha sido ${action}.\n\nPastor/a: ${pastorName}\nFecha: ${date}\nHora: ${time}\nMotivo: ${motiveLabel}\n\nSi necesitas cancelar o modificar tu cita, abre la app y ve a "Mis Citas".`;

  const subjectPastor = `📅 Nueva cita: ${userName} — ${date} ${time}`;
  const messagePastor = `Nueva cita ${action}.\n\nMiembro: ${userName}\nTeléfono: ${userPhone}\nFecha: ${date}\nHora: ${time}\nMotivo: ${motiveLabel}`;

  const results = { member:null, pastor:null };

  try {
    const r = await sendViaEmailJS({ to_email:userEmail, to_name:userName, subject:subjectMember, message:messageMember });
    results.member = r.ok ? "ok" : `HTTP ${r.status}: ${r.text}`;
    if(!r.ok) console.error("Error correo miembro:", r.status, r.text);
  } catch(e) { results.member = "fetch_failed: "+e.message; }

  if (pastorEmail) {
    try {
      const r = await sendViaEmailJS({ to_email:pastorEmail, to_name:pastorName, subject:subjectPastor, message:messagePastor });
      results.pastor = r.ok ? "ok" : `HTTP ${r.status}: ${r.text}`;
      if(!r.ok) console.error("Error correo pastor:", r.status, r.text);
    } catch(e) { results.pastor = "fetch_failed: "+e.message; }
  }

  return results;
}

/* ── BOOKING FLOW ── */
function BookingFlow({user,availability,appointments,setAppointments,setNotifications,onDone,editApt=null}) {
  const isEdit=!!editApt;
  const [step,setStep]     =useState(1);
  const [pastor,setPastor] =useState(isEdit?PASTORS.find(p=>p.id===editApt.pastorId):null);
  const [motive,setMotive] =useState(isEdit?editApt.motive:"");
  const [extra,setExtra]   =useState(isEdit?editApt.extraNote:"");
  const [calY,setCalY]     =useState(new Date().getFullYear());
  const [calM,setCalM]     =useState(new Date().getMonth());
  const [selDay,setSelDay] =useState(null);
  const [selTime,setSelTime]=useState(null);

  const avail=pastor?(availability[pastor.id]||{}):{};

  const buildCal=()=>{
    const days=getDays(calY,calM),first=getFirst(calY,calM);
    const cells=Array(first).fill(null);
    for(let d=1;d<=days;d++) cells.push(d);
    return cells;
  };

  const bookedTimes=(day)=>appointments
    .filter(a=>a.pastorId===pastor?.id&&a.dateKey===dateKey(calY,calM,day)&&a.status==="confirmed"&&(!isEdit||a.id!==editApt.id))
    .map(a=>a.time);

  const dayStatus=d=>{
    if(!d) return null;
    if(isInPast(calY,calM,d)) return "past";
    const slots=avail[dateKey(calY,calM,d)]||[];
    const bt=bookedTimes(d);
    return slots.filter(t=>!bt.includes(t)).length>0?"open":"busy";
  };

  const times=selDay?(avail[dateKey(calY,calM,selDay)]||[]).filter(t=>!bookedTimes(selDay).includes(t)):[];

  const motiveObj=MOTIVES.find(m=>m.id===motive);

  const confirm=async()=>{
    const apt={
      ts:new Date(calY,calM,selDay).getTime(),
      userId:user.id,userName:user.name,userPhone:user.phone,userEmail:user.email,
      pastorId:pastor.id,pastorName:`${pastor.name} ${pastor.surname}`,
      motive,extraNote:extra,motiveLabel:motiveObj?.label||motive,
      date:fmtDate(calY,calM,selDay),dateKey:dateKey(calY,calM,selDay),
      time:selTime,year:calY,month:calM,day:selDay,status:"confirmed",
    };
    try{
      if(isEdit){
        await updateAppointment(editApt.id, apt);
      } else {
        await createAppointment(apt);
      }
      const action=isEdit?"modificada":"confirmada";
      await Promise.all([
        createNotification({ts:Date.now(),read:false,targetId:pastor.id,type:"new_appointment",msg:`Cita ${action}: ${user.name} el ${fmtDate(calY,calM,selDay)} a las ${selTime}.`}),
        createNotification({ts:Date.now(),read:false,targetId:user.id,type:"confirmation",msg:`Tu cita con ${pastor.name} el ${fmtDate(calY,calM,selDay)} a las ${selTime} fue ${action}.`}),
        createNotification({ts:Date.now(),read:false,targetId:"secretary",type:"new_appointment",msg:`Cita ${action}: ${user.name} con ${pastor.name} el ${fmtDate(calY,calM,selDay)} a las ${selTime}.`}),
      ]);
      // Enviar correos reales de confirmación
      const pastorEmail = await getPastorEmail(pastor.id).catch(()=>null);
      const emailResults = await sendConfirmationEmails({
        userName: user.name,
        userEmail: user.email,
        userPhone: user.phone,
        pastorName: `${pastor.name} ${pastor.surname}`,
        pastorEmail,
        date: fmtDate(calY,calM,selDay),
        time: selTime,
        motiveLabel: motiveObj?.label||motive,
        action,
      });
      console.log("DEBUG resultado envío de correos:", emailResults);
      if(emailResults.member!=="ok") alert("DEBUG correo miembro: "+emailResults.member);
      setStep(5);
    }catch(e){
      alert("Error al guardar la cita. Intenta de nuevo.");
    }
  };

  const canGo2=motive&&(motive!=="otros"||extra.trim().length>=5);

  return (
    <div style={{minHeight:"100vh",background:C.snow,display:"flex",flexDirection:"column"}}>
      <div style={{background:grad,padding:"52px 16px 20px",position:"sticky",top:0,zIndex:10}}>
        <div style={{display:"flex",alignItems:"center",gap:12}}>
          {step<5&&<button onClick={()=>step>1?setStep(s=>s-1):onDone()} style={{background:"rgba(255,255,255,.18)",border:"none",color:C.white,borderRadius:10,padding:"8px 13px",cursor:"pointer",fontSize:18}}>‹</button>}
          <div style={{flex:1}}>
            <p style={{color:"rgba(255,255,255,.6)",margin:"0 0 2px",fontSize:11,fontWeight:600}}>{isEdit?"MODIFICAR":"NUEVA CITA"} · PASO {Math.min(step,4)} DE 4</p>
            <h3 style={{color:C.white,margin:0,fontSize:17,fontWeight:800}}>{["","Elegir Pastor","Motivo","Seleccionar Fecha","Confirmar",""][step]}</h3>
          </div>
        </div>
        {step<5&&<div style={{display:"flex",gap:4,marginTop:12}}>{[1,2,3,4].map(i=><div key={i} style={{flex:1,height:3,borderRadius:3,background:i<=step?"rgba(255,255,255,.9)":"rgba(255,255,255,.25)"}}/>)}</div>}
      </div>

      <div style={{padding:"16px",flex:1,paddingBottom:32}}>
        {/* STEP 1 — Pastor */}
        {step===1&&(
          <div style={{display:"flex",flexDirection:"column",gap:10}}>
            {PASTORS.map(p=>(
              <button key={p.id} onClick={()=>{setPastor(p);setStep(2);}} style={{background:C.white,border:`2.5px solid ${pastor?.id===p.id?p.color:C.mist}`,borderRadius:18,padding:"16px",cursor:"pointer",display:"flex",alignItems:"center",gap:14,textAlign:"left",width:"100%",boxShadow:pastor?.id===p.id?`0 4px 16px rgba(27,63,139,0.15)`:"none"}}>
                <div style={{width:56,height:56,borderRadius:15,background:p.colorSoft,display:"flex",alignItems:"center",justifyContent:"center",fontSize:28,flexShrink:0}}>{p.icon}</div>
                <div style={{flex:1}}><p style={{margin:"0 0 4px",fontWeight:900,color:C.ink,fontSize:16}}>{p.name} {p.surname}</p><span style={S.badge(p.color)}>{p.role}</span></div>
                <span style={{fontSize:20,color:C.grayLight}}>›</span>
              </button>
            ))}
          </div>
        )}

        {/* STEP 2 — Motive */}
        {step===2&&(
          <div style={{display:"flex",flexDirection:"column",gap:14}}>
            <div style={{...S.card,display:"flex",gap:12,alignItems:"center"}}>
              <div style={{width:48,height:48,borderRadius:13,background:pastor.colorSoft,display:"flex",alignItems:"center",justifyContent:"center",fontSize:24,flexShrink:0}}>{pastor.icon}</div>
              <div><p style={{margin:"0 0 2px",fontWeight:800,color:C.ink}}>{pastor.name} {pastor.surname}</p><span style={S.badge(pastor.color)}>{pastor.role}</span></div>
            </div>
            <MotiveSelector value={motive} extraNote={extra} onChange={setMotive} onNoteChange={setExtra}/>
            <p style={{fontSize:11,color:C.gray,margin:0}}>🔒 Información confidencial — solo la verá el pastor.</p>
            <button style={{...S.btn(),opacity:canGo2?1:.5}} disabled={!canGo2} onClick={()=>setStep(3)}>Continuar →</button>
          </div>
        )}

        {/* STEP 3 — Calendar */}
        {step===3&&(
          <div style={{display:"flex",flexDirection:"column",gap:12}}>
            <div style={S.card}>
              <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:14}}>
                <button onClick={()=>{if(calM===0){setCalM(11);setCalY(y=>y-1);}else setCalM(m=>m-1);setSelDay(null);setSelTime(null);}} style={{background:C.fog,border:"none",borderRadius:9,padding:"6px 12px",cursor:"pointer",fontWeight:700,color:C.slate}}>‹</button>
                <p style={{margin:0,fontWeight:800,color:C.ink,fontSize:15}}>{MONTHS_ES[calM]} {calY}</p>
                <button onClick={()=>{if(calM===11){setCalM(0);setCalY(y=>y+1);}else setCalM(m=>m+1);setSelDay(null);setSelTime(null);}} style={{background:C.fog,border:"none",borderRadius:9,padding:"6px 12px",cursor:"pointer",fontWeight:700,color:C.slate}}>›</button>
              </div>
              <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:2,marginBottom:6}}>
                {DAYS_ES.map(d=><p key={d} style={{margin:0,textAlign:"center",fontSize:10,fontWeight:700,color:C.gray}}>{d}</p>)}
              </div>
              <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:3}}>
                {buildCal().map((d,i)=>{
                  const st=dayStatus(d);const isSel=selDay===d;
                  const bg=!d?"transparent":isSel?C.blue:st==="open"?C.greenLight:st==="past"?C.snow:C.redLight;
                  const col=isSel?C.white:st==="open"?C.green:st==="past"?C.grayLight:st==="busy"?C.red:C.grayLight;
                  return <button key={i} disabled={!d||st==="busy"||st==="past"} onClick={()=>{setSelDay(d===selDay?null:d);setSelTime(null);}} style={{border:"none",borderRadius:9,padding:"9px 2px",cursor:d&&st==="open"?"pointer":"default",background:bg,color:col,fontWeight:isSel?900:st==="open"?700:400,fontSize:13}}>{d||""}</button>;
                })}
              </div>
              <div style={{display:"flex",gap:10,marginTop:12,justifyContent:"center",flexWrap:"wrap"}}>
                {[[C.greenLight,C.green,"Disponible"],[C.redLight,C.red,"No disponible"],[C.blue,C.white,"Seleccionado"]].map(([bg,c,lbl])=>(
                  <div key={lbl} style={{display:"flex",alignItems:"center",gap:4}}><div style={{width:12,height:12,borderRadius:3,background:bg,border:`1.5px solid ${c}44`}}/><span style={{fontSize:9,color:C.gray}}>{lbl}</span></div>
                ))}
              </div>
            </div>
            {selDay&&(
              <div style={S.card}>
                <p style={{...S.label,marginBottom:12}}>HORAS — {fmtDate(calY,calM,selDay)}</p>
                {times.length===0
                  ?<p style={{color:C.gray,fontSize:13,textAlign:"center",padding:"8px 0"}}>Sin horarios disponibles.</p>
                  :<div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8}}>
                    {times.map(t=><button key={t} onClick={()=>setSelTime(t)} style={{background:selTime===t?C.blue:C.fog,color:selTime===t?C.white:C.slate,border:`2px solid ${selTime===t?C.blue:C.mist}`,borderRadius:11,padding:"11px 4px",fontWeight:700,fontSize:14,cursor:"pointer"}}>{t}</button>)}
                  </div>
                }
              </div>
            )}
            <button style={{...S.btn(),opacity:(!selDay||!selTime)?.45:1}} disabled={!selDay||!selTime} onClick={()=>setStep(4)}>Revisar cita →</button>
          </div>
        )}

        {/* STEP 4 — Confirm */}
        {step===4&&(
          <div style={{display:"flex",flexDirection:"column",gap:12}}>
            <div style={{...S.card,background:gradSoft,border:`1px solid ${C.mist}`}}>
              <p style={{margin:"0 0 16px",fontWeight:900,color:C.navy,fontSize:17}}>Resumen de tu cita</p>
              {[
                [pastor.icon+" Pastor",`${pastor.name} ${pastor.surname}`],
                ["📅 Fecha",fmtDate(calY,calM,selDay)],
                ["⏰ Hora",selTime],
                [(motiveObj?.icon||"📝")+" Motivo",motiveObj?.label||motive],
                motive==="otros"?["📝 Nota",extra]:null,
              ].filter(Boolean).map(([k,v])=>(
                <div key={k} style={{display:"flex",gap:10,marginBottom:10,alignItems:"flex-start"}}>
                  <span style={{fontSize:13,color:C.gray,minWidth:90,fontWeight:600,flexShrink:0}}>{k}</span>
                  <span style={{fontSize:13,color:C.ink,flex:1,fontWeight:600}}>{v}</span>
                </div>
              ))}
            </div>
            <div style={{...S.card,background:C.greenLight,border:`1px solid ${C.green}33`}}>
              <p style={{margin:0,fontSize:13,color:C.green,fontWeight:700}}>✅ Al confirmar recibirás notificación y el pastor será avisado.</p>
            </div>
            <button style={S.btn(C.green)} onClick={confirm}>{isEdit?"💾 Guardar Cambios":"✅ Confirmar Cita"}</button>
            <button style={S.outline()} onClick={()=>setStep(3)}>‹ Cambiar fecha u hora</button>
          </div>
        )}

        {/* STEP 5 — Success */}
        {step===5&&(
          <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:16,padding:"24px 0",textAlign:"center"}}>
            <div style={{width:88,height:88,borderRadius:26,background:C.greenLight,border:`2px solid ${C.green}33`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:46}}>✅</div>
            <div>
              <h2 style={{margin:"0 0 8px",color:C.ink,fontSize:24,fontWeight:900}}>{isEdit?"¡Cita modificada!":"¡Cita confirmada!"}</h2>
              <p style={{margin:0,color:C.slate,fontSize:14,lineHeight:1.65}}>Tu cita con <strong>{pastor.name}</strong><br/>el <strong>{fmtDate(calY,calM,selDay)}</strong> a las <strong>{selTime}</strong><br/>ha sido registrada.</p>
            </div>
            <div style={{...S.card,width:"100%",textAlign:"left"}}>
              <p style={{margin:"0 0 4px",fontWeight:700,color:C.gray,fontSize:11}}>📧 CONFIRMACIÓN ENVIADA A</p>
              <p style={{margin:0,fontWeight:700,color:C.blue,fontSize:14}}>{user.email}</p>
            </div>
            <button style={{...S.btn(C.blueMid),marginTop:4}} onClick={()=>alert(`📅 Añadir al Calendario\n\nEvento: Cita con ${pastor.name}\nFecha: ${fmtDate(calY,calM,selDay)}\nHora: ${selTime}\nLugar: Av. de Valencia 41, Zaragoza\n\n(En producción abre el calendario nativo iOS/Android.)`)} >📅 Añadir al Calendario</button>
            <button style={{...S.outline(),marginTop:4}} onClick={onDone}>Volver al Inicio</button>
          </div>
        )}
      </div>
    </div>
  );
}

/* ── MY APPOINTMENTS ── */
function MyAppointments({user,appointments,setAppointments,availability,setNotifications,toast}) {
  const [editApt,setEditApt]=useState(null);
  const [cancelTarget,setCancelTarget]=useState(null);
  const myApts=appointments.filter(a=>a.userId===user.id).sort((a,b)=>b.ts-a.ts);
  const doCancel=async id=>{
    const apt=appointments.find(a=>a.id===id);
    try{
      await updateAppointment(id,{status:"cancelled"});
      if(apt){
        await Promise.all([
          createNotification({ts:Date.now(),read:false,targetId:apt.pastorId,type:"cancellation",msg:`${user.name} canceló su cita del ${apt.date} a las ${apt.time}.`}),
          createNotification({ts:Date.now(),read:false,targetId:"secretary",type:"cancellation",msg:`Cita cancelada: ${user.name} con ${apt.pastorName} el ${apt.date}.`}),
        ]);
      }
      toast("Cita cancelada","info");
    }catch(e){ toast("Error al cancelar","error"); }
    setCancelTarget(null);
  };
  if(editApt) return <BookingFlow user={user} availability={availability} appointments={appointments} setAppointments={setAppointments} setNotifications={setNotifications} editApt={editApt} onDone={()=>setEditApt(null)}/>;
  const confirmed=myApts.filter(a=>a.status==="confirmed");
  const past=myApts.filter(a=>a.status!=="confirmed");
  return (
    <div style={{paddingBottom:84}}>
      <div style={{background:grad,padding:"52px 20px 28px"}}>
        <h2 style={{color:C.white,margin:"0 0 4px",fontSize:24,fontWeight:900}}>Mis Citas</h2>
        <p style={{color:"rgba(255,255,255,.65)",margin:0,fontSize:13}}>{confirmed.length} activa{confirmed.length!==1?"s":""}</p>
      </div>
      <div style={{padding:"16px"}}>
        {myApts.length===0?(
          <div style={{textAlign:"center",padding:"56px 16px"}}>
            <div style={{fontSize:52,marginBottom:12}}>📋</div>
            <p style={{fontWeight:700,color:C.slate,fontSize:16,margin:"0 0 6px"}}>Sin citas agendadas</p>
            <p style={{color:C.gray,fontSize:13}}>Regresa al inicio y agenda tu primera cita.</p>
          </div>
        ):(
          <>
            {confirmed.length>0&&<p style={{...S.label,marginBottom:8}}>PRÓXIMAS</p>}
            {confirmed.map(a=>{
              const mo=MOTIVES.find(m=>m.id===a.motive);
              return (
                <div key={a.id} style={{...S.card,borderLeft:`4px solid ${C.blue}`}}>
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:8}}>
                    <div><p style={{margin:"0 0 2px",fontWeight:800,color:C.ink,fontSize:15}}>{a.pastorName}</p><p style={{margin:0,fontSize:13,color:C.slate}}>📅 {a.date} · ⏰ {a.time}</p></div>
                    <span style={S.badge(C.green)}>Confirmada</span>
                  </div>
                  <div style={{background:C.blueMist,borderRadius:10,padding:"8px 10px",marginBottom:10,display:"flex",alignItems:"center",gap:8}}>
                    <span style={{fontSize:20}}>{mo?.icon||"📝"}</span>
                    <p style={{margin:0,fontSize:13,color:C.slate,fontWeight:600}}>{a.motiveLabel}{a.motive==="otros"&&a.extraNote?` — ${a.extraNote.slice(0,40)}…`:""}</p>
                  </div>
                  <div style={{display:"flex",gap:8}}>
                    <button onClick={()=>setEditApt(a)} style={S.btnSm(C.blueFrost,C.blue)}>✏️ Modificar</button>
                    <button onClick={()=>setCancelTarget(a)} style={S.btnSm(C.redLight,C.red)}>❌ Cancelar</button>
                  </div>
                </div>
              );
            })}
            {past.length>0&&<p style={{...S.label,marginTop:8,marginBottom:8}}>HISTORIAL</p>}
            {past.map(a=>(
              <div key={a.id} style={{...S.card,borderLeft:`4px solid ${C.mist}`,opacity:.7}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                  <div><p style={{margin:"0 0 2px",fontWeight:700,color:C.slate,fontSize:14}}>{a.pastorName}</p><p style={{margin:0,fontSize:12,color:C.gray}}>📅 {a.date} · ⏰ {a.time}</p></div>
                  <span style={S.badge(C.mist,C.slate)}>{a.status==="cancelled"?"Cancelada":"Pasada"}</span>
                </div>
              </div>
            ))}
          </>
        )}
      </div>
      <Modal open={!!cancelTarget} onClose={()=>setCancelTarget(null)} title="¿Cancelar esta cita?">
        {cancelTarget&&(
          <>
            <div style={{...S.card,background:C.redLight,border:`1px solid ${C.red}33`,marginBottom:14}}>
              <p style={{margin:"0 0 4px",fontWeight:700,color:C.red}}>Vas a cancelar:</p>
              <p style={{margin:"0 0 2px",fontSize:14,color:C.ink}}>👤 {cancelTarget.pastorName}</p>
              <p style={{margin:0,fontSize:14,color:C.ink}}>📅 {cancelTarget.date} · {cancelTarget.time}</p>
            </div>
            <button style={S.btn(C.red)} onClick={()=>doCancel(cancelTarget.id)}>Sí, cancelar cita</button>
            <button style={{...S.outline(),marginTop:10}} onClick={()=>setCancelTarget(null)}>Volver</button>
          </>
        )}
      </Modal>
    </div>
  );
}

/* ── PASTOR HOME ── */
function PastorHome({user,appointments}) {
  const pastor=PASTORS.find(p=>p.id===user.pastorId);
  const myApts=appointments.filter(a=>a.pastorId===user.pastorId&&a.status==="confirmed");
  const today=new Date();today.setHours(0,0,0,0);
  const todayApts=myApts.filter(a=>new Date(a.year,a.month,a.day).getTime()===today.getTime());
  const upcoming=myApts.filter(a=>new Date(a.year,a.month,a.day)>today).sort((a,b)=>a.ts-b.ts).slice(0,5);
  const hour=new Date().getHours();
  const greeting=hour<12?"Buenos días ☀️":hour<19?"Buenas tardes 🌤️":"Buenas noches 🌙";
  return (
    <div style={{paddingBottom:84}}>
      <div style={{background:grad,padding:"52px 20px 28px",position:"relative",overflow:"hidden"}}>
        <div style={{position:"absolute",top:-50,right:-50,width:160,height:160,borderRadius:"50%",background:"rgba(255,255,255,.05)"}}/>
        <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",marginBottom:20}}>
          <div>
            <p style={{color:"rgba(255,255,255,.65)",margin:"0 0 3px",fontSize:13}}>{greeting}</p>
            <h2 style={{color:C.white,margin:"0 0 4px",fontSize:22,fontWeight:900}}>{pastor?.name} {pastor?.surname}</h2>
            <span style={S.badge("rgba(255,255,255,.2)",C.white)}>{pastor?.role}</span>
          </div>
          <div style={{width:50,height:50,borderRadius:14,background:"rgba(255,255,255,.12)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:26,border:"1px solid rgba(255,255,255,.2)"}}>{pastor?.icon}</div>
        </div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8}}>
          {[["📅","Hoy",todayApts.length],["🗓️","Próximas",upcoming.length],["📋","Total",myApts.length]].map(([icon,lbl,val])=>(
            <div key={lbl} style={{background:"rgba(255,255,255,.12)",borderRadius:13,padding:"10px 6px",textAlign:"center",border:"1px solid rgba(255,255,255,.15)"}}>
              <p style={{margin:"0 0 2px",fontSize:18}}>{icon}</p>
              <p style={{margin:"0 0 1px",fontSize:20,fontWeight:900,color:C.white}}>{val}</p>
              <p style={{margin:0,fontSize:9,color:"rgba(255,255,255,.6)",fontWeight:600,textTransform:"uppercase"}}>{lbl}</p>
            </div>
          ))}
        </div>
      </div>
      <div style={{padding:"16px"}}>
        {todayApts.length>0&&(
          <div style={{marginBottom:14}}>
            <p style={{...S.label,marginBottom:8}}>CITAS DE HOY</p>
            {todayApts.sort((a,b)=>a.time.localeCompare(b.time)).map(a=>{
              const mo=MOTIVES.find(m=>m.id===a.motive);
              return (
                <div key={a.id} style={{...S.card,borderLeft:`4px solid ${C.gold}`}}>
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:6}}>
                    <p style={{margin:0,fontWeight:800,color:C.ink}}>{a.userName}</p>
                    <span style={S.badge(C.gold)}>⏰ {a.time}</span>
                  </div>
                  <p style={{margin:"0 0 6px",fontSize:12,color:C.slate}}>📞 {a.userPhone}</p>
                  <div style={{background:C.blueMist,borderRadius:8,padding:"6px 10px",display:"flex",gap:6,alignItems:"center"}}>
                    <span>{mo?.icon||"📝"}</span>
                    <p style={{margin:0,fontSize:12,color:C.slate,fontWeight:600}}>{a.motiveLabel}{a.motive==="otros"&&a.extraNote?` — ${a.extraNote}`:""}</p>
                  </div>
                </div>
              );
            })}
          </div>
        )}
        <p style={{...S.label,marginBottom:8}}>PRÓXIMAS CITAS</p>
        {upcoming.length===0
          ?<div style={{...S.card,textAlign:"center",padding:"24px"}}><p style={{color:C.gray,margin:0,fontSize:13}}>No tienes citas próximas.</p></div>
          :upcoming.map(a=>{
            const mo=MOTIVES.find(m=>m.id===a.motive);
            return (
              <div key={a.id} style={{...S.card,borderLeft:`4px solid ${C.blue}`}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:4}}>
                  <p style={{margin:0,fontWeight:800,color:C.ink}}>{a.userName}</p>
                  <span style={S.badge(C.blue)}>{a.time}</span>
                </div>
                <p style={{margin:"0 0 2px",fontSize:12,color:C.slate}}>📅 {a.date}</p>
                <p style={{margin:"0 0 6px",fontSize:12,color:C.gray}}>📞 {a.userPhone}</p>
                <div style={{background:C.blueMist,borderRadius:8,padding:"6px 10px",display:"flex",gap:6,alignItems:"center"}}>
                  <span>{mo?.icon||"📝"}</span>
                  <p style={{margin:0,fontSize:12,color:C.slate,fontWeight:600}}>{a.motiveLabel}{a.motive==="otros"&&a.extraNote?` — ${a.extraNote.slice(0,50)}`:""}</p>
                </div>
              </div>
            );
          })
        }
      </div>
    </div>
  );
}

/* ── PASTOR SCHEDULE ── */
function PastorSchedule({user,availability,setAvailability,appointments,toast}) {
  const [calY,setCalY]=useState(new Date().getFullYear());
  const [calM,setCalM]=useState(new Date().getMonth());
  const [selDay,setSelDay]=useState(null);
  const [bulkModal,setBulkModal]=useState(false);
  const avail=availability[user.pastorId]||{};
  const myApts=appointments.filter(a=>a.pastorId===user.pastorId&&a.status==="confirmed");
  const toggleTime=async(d,t)=>{
    const k=dateKey(calY,calM,d);
    const cur=(avail[k]||[]);
    const updated=cur.includes(t)?cur.filter(x=>x!==t):[...cur,t].sort();
    try{ await setAvailability(user.pastorId,k,updated); }
    catch(e){ toast("Error al guardar","error"); }
  };
  const clearDay=async d=>{
    const k=dateKey(calY,calM,d);
    try{ await setAvailability(user.pastorId,k,[]); toast("Día limpiado","info"); }
    catch(e){ toast("Error al limpiar","error"); }
  };
  const setAllDay=async d=>{
    const k=dateKey(calY,calM,d);
    try{ await setAvailability(user.pastorId,k,[...ALL_TIMES]); toast("Todos los horarios activados"); }
    catch(e){ toast("Error al guardar","error"); }
  };
  const applyWeekly=async(dows,times)=>{
    const updates=[];
    for(let d=1;d<=getDays(calY,calM);d++){
      if(isInPast(calY,calM,d))continue;
      const dow=new Date(calY,calM,d).getDay();
      if(dows.includes(dow)) updates.push({k:dateKey(calY,calM,d),times:[...times]});
    }
    try{
      await Promise.all(updates.map(({k,times:t})=>setAvailability(user.pastorId,k,t)));
      toast("Disponibilidad semanal aplicada"); setBulkModal(false);
    }catch(e){ toast("Error al aplicar","error"); }
  };
  const buildCal=()=>{const days=getDays(calY,calM),first=getFirst(calY,calM);const cells=Array(first).fill(null);for(let d=1;d<=days;d++)cells.push(d);return cells;};
  const selAvailTimes=selDay?(avail[dateKey(calY,calM,selDay)]||[]):[];
  const bookedTimes=selDay?myApts.filter(a=>a.dateKey===dateKey(calY,calM,selDay)).map(a=>a.time):[];
  return (
    <div style={{paddingBottom:84}}>
      <div style={{background:grad,padding:"52px 20px 24px"}}>
        <h2 style={{color:C.white,margin:"0 0 4px",fontSize:24,fontWeight:900}}>Mi Disponibilidad</h2>
        <p style={{color:"rgba(255,255,255,.65)",margin:0,fontSize:13}}>Configura tus horarios disponibles</p>
      </div>
      <div style={{padding:"16px"}}>
        <div style={{...S.card,display:"flex",alignItems:"center",justifyContent:"space-between"}}>
          <p style={{margin:0,fontSize:13,color:C.slate,fontWeight:600}}>Configuración rápida</p>
          <button onClick={()=>setBulkModal(true)} style={S.btnSm()}>📅 Configurar semana</button>
        </div>
        <div style={S.card}>
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:14}}>
            <button onClick={()=>{if(calM===0){setCalM(11);setCalY(y=>y-1);}else setCalM(m=>m-1);setSelDay(null);}} style={{background:C.fog,border:"none",borderRadius:9,padding:"6px 12px",cursor:"pointer",fontWeight:700,color:C.slate}}>‹</button>
            <p style={{margin:0,fontWeight:800,color:C.ink,fontSize:15}}>{MONTHS_ES[calM]} {calY}</p>
            <button onClick={()=>{if(calM===11){setCalM(0);setCalY(y=>y+1);}else setCalM(m=>m+1);setSelDay(null);}} style={{background:C.fog,border:"none",borderRadius:9,padding:"6px 12px",cursor:"pointer",fontWeight:700,color:C.slate}}>›</button>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:2,marginBottom:6}}>
            {DAYS_ES.map(d=><p key={d} style={{margin:0,textAlign:"center",fontSize:10,fontWeight:700,color:C.gray}}>{d}</p>)}
          </div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:3}}>
            {buildCal().map((d,i)=>{
              const slots=d?(avail[dateKey(calY,calM,d)]||[]):[];const isSel=selDay===d;const isPast=d&&isInPast(calY,calM,d);
              const hasBook=d&&myApts.some(a=>a.dateKey===dateKey(calY,calM,d));
              const bg=!d?"transparent":isSel?C.blue:slots.length>0?C.greenLight:C.fog;
              const col=isSel?C.white:slots.length>0?C.green:isPast?C.grayLight:C.slate;
              return <button key={i} disabled={!d||isPast} onClick={()=>setSelDay(d===selDay?null:d)} style={{border:"none",borderRadius:9,padding:"9px 2px",cursor:d&&!isPast?"pointer":"default",background:bg,color:col,fontWeight:isSel?900:slots.length>0?700:400,fontSize:13,position:"relative"}}>
                {d||""}{hasBook&&!isSel&&<div style={{position:"absolute",bottom:2,left:"50%",transform:"translateX(-50%)",width:4,height:4,borderRadius:"50%",background:C.gold}}/>}
              </button>;
            })}
          </div>
          <div style={{display:"flex",gap:10,marginTop:12,justifyContent:"center",flexWrap:"wrap"}}>
            {[[C.greenLight,C.green,"Disponible"],[C.fog,C.slate,"Sin horarios"]].map(([bg,c,lbl])=>(
              <div key={lbl} style={{display:"flex",alignItems:"center",gap:4}}><div style={{width:12,height:12,borderRadius:3,background:bg,border:`1.5px solid ${c}44`}}/><span style={{fontSize:9,color:C.gray}}>{lbl}</span></div>
            ))}
            <div style={{display:"flex",alignItems:"center",gap:4}}><div style={{width:5,height:5,borderRadius:"50%",background:C.gold}}/><span style={{fontSize:9,color:C.gray}}>Con cita</span></div>
          </div>
        </div>
        {selDay&&(
          <div style={S.card}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12}}>
              <p style={{...S.label,margin:0}}>HORARIOS — {fmtDate(calY,calM,selDay)}</p>
              <div style={{display:"flex",gap:6}}>
                <button onClick={()=>setAllDay(selDay)} style={S.btnSm(C.greenLight,C.green)}>Todo</button>
                <button onClick={()=>clearDay(selDay)} style={S.btnSm(C.redLight,C.red)}>Limpiar</button>
              </div>
            </div>
            <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:6}}>
              {ALL_TIMES.map(t=>{
                const isOn=selAvailTimes.includes(t);const isBook=bookedTimes.includes(t);
                return <div key={t} style={{position:"relative"}}>
                  <button onClick={()=>!isBook&&toggleTime(selDay,t)} disabled={isBook} style={{background:isBook?C.amberLight:isOn?C.green:C.fog,color:isBook?C.amber:isOn?C.white:C.slate,border:`2px solid ${isBook?C.gold:isOn?C.green:C.mist}`,borderRadius:10,padding:"9px 4px",fontWeight:700,fontSize:12,cursor:isBook?"default":"pointer",width:"100%"}}>{t}</button>
                  {isBook&&<div style={{position:"absolute",top:-4,right:-4,background:C.gold,color:C.white,fontSize:9,fontWeight:800,borderRadius:6,padding:"1px 4px"}}>📌</div>}
                </div>;
              })}
            </div>
            <p style={{fontSize:11,color:C.gray,marginTop:8}}>🟢 Disponible · 📌 Cita agendada</p>
          </div>
        )}
        <p style={{...S.label,marginTop:4,marginBottom:8}}>TODAS LAS CITAS</p>
        {myApts.length===0
          ?<div style={{...S.card,textAlign:"center",padding:"20px"}}><p style={{color:C.gray,margin:0}}>No tienes citas agendadas.</p></div>
          :myApts.sort((a,b)=>a.ts-b.ts).map(a=>{
            const mo=MOTIVES.find(m=>m.id===a.motive);
            return (
              <div key={a.id} style={{...S.card,borderLeft:`4px solid ${C.blue}`}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:4}}>
                  <p style={{margin:0,fontWeight:800,color:C.ink,fontSize:14}}>{a.userName}</p>
                  <span style={S.badge(C.blue)}>{a.time}</span>
                </div>
                <p style={{margin:"0 0 4px",fontSize:12,color:C.slate}}>📅 {a.date} · 📞 {a.userPhone}</p>
                <div style={{background:C.blueMist,borderRadius:8,padding:"5px 8px",display:"flex",gap:6,alignItems:"center"}}>
                  <span>{mo?.icon||"📝"}</span>
                  <p style={{margin:0,fontSize:11,color:C.slate,fontWeight:600}}>{a.motiveLabel}{a.motive==="otros"&&a.extraNote?` — ${a.extraNote}`:""}</p>
                </div>
              </div>
            );
          })
        }
      </div>
      <Modal open={bulkModal} onClose={()=>setBulkModal(false)} title="Configurar disponibilidad semanal">
        <BulkWeeklyEditor onApply={applyWeekly} onClose={()=>setBulkModal(false)}/>
      </Modal>
    </div>
  );
}

function BulkWeeklyEditor({onApply,onClose}) {
  const [dows,setDows]=useState([2,4]);
  const [times,setTimes]=useState(["10:00","11:00","16:00","17:00"]);
  const td=d=>setDows(ds=>ds.includes(d)?ds.filter(x=>x!==d):[...ds,d]);
  const tt=t=>setTimes(ts=>ts.includes(t)?ts.filter(x=>x!==t):[...ts,t]);
  return (
    <div>
      <p style={{...S.label,marginBottom:8}}>DÍAS DE LA SEMANA</p>
      <div style={{display:"flex",gap:6,flexWrap:"wrap",marginBottom:16}}>
        {DAYS_ES.map((d,i)=><button key={i} onClick={()=>td(i)} style={{background:dows.includes(i)?C.blue:C.fog,color:dows.includes(i)?C.white:C.slate,border:"none",borderRadius:9,padding:"8px 10px",fontWeight:700,fontSize:13,cursor:"pointer"}}>{d}</button>)}
      </div>
      <p style={{...S.label,marginBottom:8}}>HORARIOS</p>
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:6,marginBottom:20}}>
        {ALL_TIMES.map(t=><button key={t} onClick={()=>tt(t)} style={{background:times.includes(t)?C.green:C.fog,color:times.includes(t)?C.white:C.slate,border:`2px solid ${times.includes(t)?C.green:C.mist}`,borderRadius:10,padding:"9px 4px",fontWeight:700,fontSize:12,cursor:"pointer"}}>{t}</button>)}
      </div>
      <p style={{fontSize:12,color:C.gray,marginBottom:14}}>Sobrescribirá los días seleccionados del mes actual.</p>
      <button style={{...S.btn(),opacity:dows.length===0||times.length===0?.5:1}} disabled={dows.length===0||times.length===0} onClick={()=>onApply(dows,times)}>Aplicar al mes</button>
      <button style={{...S.outline(),marginTop:10}} onClick={onClose}>Cancelar</button>
    </div>
  );
}

/* ── SECRETARY PANEL ── */
function SecretaryPanel({user,availability,appointments,notifications,setNotifications}) {
  const [selPId,setSelPId]=useState(PASTORS[0].id);
  const [calY,setCalY]=useState(new Date().getFullYear());
  const [calM,setCalM]=useState(new Date().getMonth());
  const [selDay,setSelDay]=useState(null);
  const [tab,setTab]=useState("calendar");
  const [filterPId,setFilterPId]=useState("all");
  const pastor=PASTORS.find(p=>p.id===selPId);
  const avail=availability[selPId]||{};
  const myApts=appointments.filter(a=>a.pastorId===selPId&&a.status==="confirmed").sort((a,b)=>a.ts-b.ts);
  const today=new Date();today.setHours(0,0,0,0);
  const allUpcoming=appointments.filter(a=>a.status==="confirmed"&&new Date(a.year,a.month,a.day)>today);
  const todayAll=appointments.filter(a=>a.status==="confirmed"&&new Date(a.year,a.month,a.day).getTime()===today.getTime());
  const buildCal=()=>{const days=getDays(calY,calM),first=getFirst(calY,calM);const cells=Array(first).fill(null);for(let d=1;d<=days;d++)cells.push(d);return cells;};
  const dayStatus=d=>{
    if(!d)return null;
    const k=dateKey(calY,calM,d);
    const slots=avail[k]||[];
    const booked=myApts.filter(a=>a.dateKey===k).length;
    if(isInPast(calY,calM,d))return"past";
    if(slots.length>0&&booked>0)return"partial";
    if(slots.length>0)return"open";
    return"busy";
  };
  const selSlots=selDay?(avail[dateKey(calY,calM,selDay)]||[]):[];
  const selBooked=selDay?myApts.filter(a=>a.dateKey===dateKey(calY,calM,selDay)):[];
  return (
    <div style={{paddingBottom:84}}>
      <div style={{background:gradPurple,padding:"52px 20px 24px",position:"relative",overflow:"hidden"}}>
        <div style={{position:"absolute",top:-50,right:-50,width:160,height:160,borderRadius:"50%",background:"rgba(255,255,255,.06)"}}/>
        <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",marginBottom:16}}>
          <div>
            <p style={{color:"rgba(255,255,255,.65)",margin:"0 0 3px",fontSize:13}}>Panel de Secretaría</p>
            <h2 style={{color:C.white,margin:"0 0 4px",fontSize:21,fontWeight:900}}>{user.name.split(" ").slice(0,2).join(" ")}</h2>
            <span style={S.badge("rgba(255,255,255,.22)",C.white)}>📋 Secretario/a Pastoral</span>
          </div>
          <div style={{width:48,height:48,borderRadius:14,background:"rgba(255,255,255,.15)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:24,border:"1px solid rgba(255,255,255,.2)"}}>📋</div>
        </div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8}}>
          {[["📅","Hoy",todayAll.length],["🗓️","Próximas",allUpcoming.length],["👥","Pastores",PASTORS.length]].map(([icon,lbl,val])=>(
            <div key={lbl} style={{background:"rgba(255,255,255,.13)",borderRadius:13,padding:"10px 6px",textAlign:"center",border:"1px solid rgba(255,255,255,.18)"}}>
              <p style={{margin:"0 0 2px",fontSize:18}}>{icon}</p>
              <p style={{margin:"0 0 1px",fontSize:20,fontWeight:900,color:C.white}}>{val}</p>
              <p style={{margin:0,fontSize:9,color:"rgba(255,255,255,.6)",fontWeight:600,textTransform:"uppercase"}}>{lbl}</p>
            </div>
          ))}
        </div>
      </div>
      <div style={{display:"flex",background:C.white,borderBottom:`1px solid ${C.mist}`}}>
        {[["calendar","📅 Calendario"],["appointments","📋 Citas"]].map(([id,lbl])=>(
          <button key={id} onClick={()=>{setTab(id);setSelDay(null);}} style={{flex:1,background:"none",border:"none",borderBottom:`3px solid ${tab===id?C.purple:"transparent"}`,padding:"12px 8px",cursor:"pointer",fontSize:13,fontWeight:tab===id?800:500,color:tab===id?C.purple:C.gray}}>{lbl}</button>
        ))}
      </div>
      <div style={{padding:"16px"}}>
        {tab==="calendar"&&(
          <>
            <div style={{display:"flex",gap:6,overflowX:"auto",paddingBottom:8,marginBottom:4}}>
              {PASTORS.map(p=>(
                <button key={p.id} onClick={()=>{setSelPId(p.id);setSelDay(null);}} style={{flexShrink:0,display:"flex",alignItems:"center",gap:7,background:selPId===p.id?p.color:C.white,color:selPId===p.id?C.white:C.slate,border:`2px solid ${selPId===p.id?p.color:C.mist}`,borderRadius:12,padding:"8px 12px",cursor:"pointer",fontWeight:700,fontSize:13,boxShadow:selPId===p.id?`0 4px 12px rgba(27,63,139,0.2)`:"none"}}>
                  <span style={{fontSize:16}}>{p.icon}</span>{p.name}
                </button>
              ))}
            </div>
            <div style={{...S.card,background:C.purpleLight,border:`1px solid ${C.purple}22`,padding:"10px 14px",marginBottom:12}}>
              <p style={{margin:0,fontSize:12,color:C.purple,fontWeight:700}}>🔒 Solo lectura — Agenda de {pastor?.name} {pastor?.surname}</p>
            </div>
            <div style={S.card}>
              <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:14}}>
                <button onClick={()=>{if(calM===0){setCalM(11);setCalY(y=>y-1);}else setCalM(m=>m-1);setSelDay(null);}} style={{background:C.fog,border:"none",borderRadius:9,padding:"6px 12px",cursor:"pointer",fontWeight:700,color:C.slate}}>‹</button>
                <p style={{margin:0,fontWeight:800,color:C.ink,fontSize:15}}>{MONTHS_ES[calM]} {calY}</p>
                <button onClick={()=>{if(calM===11){setCalM(0);setCalY(y=>y+1);}else setCalM(m=>m+1);setSelDay(null);}} style={{background:C.fog,border:"none",borderRadius:9,padding:"6px 12px",cursor:"pointer",fontWeight:700,color:C.slate}}>›</button>
              </div>
              <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:2,marginBottom:6}}>
                {DAYS_ES.map(d=><p key={d} style={{margin:0,textAlign:"center",fontSize:10,fontWeight:700,color:C.gray}}>{d}</p>)}
              </div>
              <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:3}}>
                {buildCal().map((d,i)=>{
                  const st=dayStatus(d);const isSel=selDay===d;
                  const bg=!d?"transparent":isSel?C.purple:st==="open"?C.greenLight:st==="partial"?C.amberLight:st==="past"?C.snow:C.redLight;
                  const col=isSel?C.white:st==="open"?C.green:st==="partial"?C.amber:st==="past"?C.grayLight:st==="busy"?C.red:C.grayLight;
                  return <button key={i} disabled={!d||st==="past"} onClick={()=>setSelDay(d===selDay?null:d)} style={{border:"none",borderRadius:9,padding:"9px 2px",cursor:d&&st!=="past"?"pointer":"default",background:bg,color:col,fontWeight:isSel?900:["open","partial"].includes(st)?700:400,fontSize:13}}>{d||""}</button>;
                })}
              </div>
              <div style={{display:"flex",gap:8,marginTop:12,justifyContent:"center",flexWrap:"wrap"}}>
                {[[C.greenLight,C.green,"Disponible"],[C.amberLight,C.amber,"Con citas"],[C.redLight,C.red,"No disponible"]].map(([bg,c,lbl])=>(
                  <div key={lbl} style={{display:"flex",alignItems:"center",gap:4}}><div style={{width:11,height:11,borderRadius:3,background:bg,border:`1.5px solid ${c}44`}}/><span style={{fontSize:9,color:C.gray}}>{lbl}</span></div>
                ))}
              </div>
            </div>
            {selDay&&(
              <div style={S.card}>
                <p style={{...S.label,marginBottom:12}}>{fmtDate(calY,calM,selDay)} — {pastor?.name}</p>
                {selSlots.length===0
                  ?<p style={{color:C.gray,fontSize:13,textAlign:"center",padding:"8px 0"}}>Sin horarios este día.</p>
                  :(
                    <>
                      <p style={{fontSize:12,fontWeight:700,color:C.slate,marginBottom:8}}>HORARIOS</p>
                      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:6,marginBottom:14}}>
                        {selSlots.map(t=>{const isBook=selBooked.some(a=>a.time===t);return(
                          <div key={t} style={{background:isBook?C.amberLight:C.greenLight,color:isBook?C.amber:C.green,border:`1.5px solid ${isBook?C.gold:C.green}44`,borderRadius:10,padding:"9px 4px",fontWeight:700,fontSize:12,textAlign:"center"}}>
                            {t}{isBook&&<div style={{fontSize:9,marginTop:2}}>📌</div>}
                          </div>
                        );})}
                      </div>
                      {selBooked.length>0&&(
                        <>
                          <p style={{fontSize:12,fontWeight:700,color:C.slate,marginBottom:8}}>CITAS AGENDADAS</p>
                          {selBooked.map(a=>(
                            <div key={a.id} style={{background:C.fog,borderRadius:12,padding:"10px 12px",marginBottom:8,borderLeft:`3px solid ${C.gold}`}}>
                              <p style={{margin:"0 0 2px",fontWeight:700,color:C.ink,fontSize:14}}>{a.userName}</p>
                              <p style={{margin:"0 0 4px",fontSize:12,color:C.slate}}>⏰ {a.time} · 📞 {a.userPhone}</p>
                              <div style={{background:C.mist,borderRadius:6,padding:"3px 8px",display:"inline-flex",alignItems:"center",gap:4}}>
                                <span style={{fontSize:11}}>🔒</span>
                                <p style={{margin:0,fontSize:10,color:C.gray}}>Motivo confidencial</p>
                              </div>
                            </div>
                          ))}
                        </>
                      )}
                    </>
                  )
                }
              </div>
            )}
          </>
        )}
        {tab==="appointments"&&(
          <>
            <div style={{...S.card,background:C.purpleLight,border:`1px solid ${C.purple}22`,padding:"10px 14px",marginBottom:8}}>
              <p style={{margin:0,fontSize:12,color:C.purple,fontWeight:700}}>🔒 El motivo de cada cita es confidencial — solo visible para el pastor.</p>
            </div>
            <div style={{display:"flex",gap:6,overflowX:"auto",paddingBottom:8,marginBottom:8}}>
              <button onClick={()=>setFilterPId("all")} style={{flexShrink:0,background:filterPId==="all"?C.purple:C.white,color:filterPId==="all"?C.white:C.slate,border:`2px solid ${filterPId==="all"?C.purple:C.mist}`,borderRadius:12,padding:"7px 12px",cursor:"pointer",fontWeight:700,fontSize:12}}>Todos</button>
              {PASTORS.map(p=>(
                <button key={p.id} onClick={()=>setFilterPId(p.id)} style={{flexShrink:0,background:filterPId===p.id?p.color:C.white,color:filterPId===p.id?C.white:C.slate,border:`2px solid ${filterPId===p.id?p.color:C.mist}`,borderRadius:12,padding:"7px 12px",cursor:"pointer",fontWeight:700,fontSize:12}}>{p.icon} {p.name}</button>
              ))}
            </div>
            {(()=>{
              const now=new Date();now.setHours(0,0,0,0);
              const list=appointments.filter(a=>a.status==="confirmed"&&(filterPId==="all"||a.pastorId===filterPId)).sort((a,b)=>a.ts-b.ts);
              if(list.length===0) return <div style={{textAlign:"center",padding:"48px 16px"}}><span style={{fontSize:48}}>📭</span><p style={{color:C.gray,fontSize:13,marginTop:12}}>No hay citas confirmadas.</p></div>;
              const upcoming=list.filter(a=>new Date(a.year,a.month,a.day)>=now);
              const past=list.filter(a=>new Date(a.year,a.month,a.day)<now);
              return (
                <>
                  {upcoming.length>0&&<p style={{...S.label,marginBottom:8}}>PRÓXIMAS ({upcoming.length})</p>}
                  {upcoming.map(a=>{const p=PASTORS.find(px=>px.id===a.pastorId);return(
                    <div key={a.id} style={{...S.card,borderLeft:`4px solid ${p?.color||C.blue}`}}>
                      <p style={{margin:"0 0 2px",fontWeight:800,color:C.ink,fontSize:15}}>{a.userName}</p>
                      <p style={{margin:"0 0 6px",fontSize:12,color:C.slate}}>📞 {a.userPhone}</p>
                      <div style={{display:"flex",gap:5,flexWrap:"wrap",marginBottom:6}}>
                        <span style={S.badge(p?.color||C.blue)}>{p?.icon} {p?.name}</span>
                        <span style={S.badge(C.fog,C.slate)}>📅 {a.date}</span>
                        <span style={S.badge(C.fog,C.slate)}>⏰ {a.time}</span>
                      </div>
                      <div style={{display:"flex",alignItems:"center",gap:5,background:C.fog,borderRadius:8,padding:"6px 10px"}}>
                        <span style={{fontSize:13}}>🔒</span>
                        <p style={{margin:0,fontSize:11,color:C.gray,fontStyle:"italic"}}>Motivo confidencial</p>
                      </div>
                    </div>
                  );})}
                  {past.length>0&&<p style={{...S.label,marginTop:8,marginBottom:8}}>HISTORIAL ({past.length})</p>}
                  {past.map(a=>{const p=PASTORS.find(px=>px.id===a.pastorId);return(
                    <div key={a.id} style={{...S.card,opacity:.65,borderLeft:`4px solid ${C.mist}`}}>
                      <p style={{margin:"0 0 2px",fontWeight:700,color:C.slate,fontSize:14}}>{a.userName}</p>
                      <p style={{margin:0,fontSize:12,color:C.gray}}>📅 {a.date} · ⏰ {a.time} · {p?.icon} {p?.name}</p>
                    </div>
                  );})}
                </>
              );
            })()}
          </>
        )}
      </div>
    </div>
  );
}

/* ── NOTIFICATIONS ── */
function NotificationsScreen({userId,userRole,notifications,onMarkRead}) {
  const isSec=userRole==="secretary";
  const mine=notifications.filter(n=>n.targetId===userId||(isSec&&n.targetId==="secretary")).sort((a,b)=>b.ts-a.ts);
  const markAll=()=>mine.filter(n=>!n.read).forEach(n=>onMarkRead(n.id));
  const markOne=id=>onMarkRead(id);
  const tIcon=t=>t==="confirmation"?"✅":t==="new_appointment"?"📅":t==="cancellation"?"❌":"🔔";
  const tColor=t=>t==="confirmation"?C.green:t==="new_appointment"?C.blue:t==="cancellation"?C.red:C.slate;
  const fmtTs=ts=>{const d=Date.now()-ts;if(d<60000)return"Ahora mismo";if(d<3600000)return`Hace ${Math.floor(d/60000)}min`;if(d<86400000)return`Hace ${Math.floor(d/3600000)}h`;return new Date(ts).toLocaleDateString("es-ES");};
  const unread=mine.filter(n=>!n.read).length;
  const bg=userRole==="secretary"?gradPurple:grad;
  return (
    <div style={{paddingBottom:84}}>
      <div style={{background:bg,padding:"52px 20px 24px",display:"flex",alignItems:"flex-start",justifyContent:"space-between"}}>
        <div>
          <h2 style={{color:C.white,margin:"0 0 4px",fontSize:24,fontWeight:900}}>Avisos</h2>
          <p style={{color:"rgba(255,255,255,.65)",margin:0,fontSize:13}}>{unread} sin leer · {mine.length} total</p>
        </div>
        {unread>0&&<button onClick={markAll} style={{background:"rgba(255,255,255,.18)",border:"none",color:C.white,borderRadius:10,padding:"8px 14px",cursor:"pointer",fontSize:12,fontWeight:700}}>Todo leído</button>}
      </div>
      <div style={{padding:"16px"}}>
        {mine.length===0?(
          <div style={{textAlign:"center",padding:"56px 16px"}}>
            <div style={{fontSize:52,marginBottom:12}}>🔔</div>
            <p style={{fontWeight:700,color:C.slate,fontSize:16,margin:"0 0 6px"}}>Sin notificaciones</p>
            <p style={{color:C.gray,fontSize:13}}>Aquí verás confirmaciones y avisos de citas.</p>
          </div>
        ):mine.map(n=>(
          <div key={n.id} onClick={()=>markOne(n.id)} style={{...S.card,display:"flex",gap:12,alignItems:"flex-start",background:n.read?C.white:`${tColor(n.type)}0A`,border:`1px solid ${n.read?C.mist:`${tColor(n.type)}33`}`,cursor:"pointer"}}>
            <div style={{width:40,height:40,borderRadius:12,background:`${tColor(n.type)}18`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:20,flexShrink:0}}>{tIcon(n.type)}</div>
            <div style={{flex:1}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:3}}>
                <p style={{margin:0,fontWeight:n.read?600:800,color:C.ink,fontSize:14,lineHeight:1.4,flex:1}}>{n.msg}</p>
                {!n.read&&<div style={{width:8,height:8,borderRadius:"50%",background:tColor(n.type),flexShrink:0,marginLeft:8,marginTop:4}}/>}
              </div>
              <p style={{margin:0,fontSize:11,color:C.gray}}>{fmtTs(n.ts)}</p>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

