/* ── PROFILE ── */
function ProfileScreen({user,setUser,onLogout,toast}) {
  const [editing,setEditing]=useState(false);
  const [form,setForm]=useState({name:user.name,phone:user.phone||"",email:user.email,nie:user.nie||""});
  const [passModal,setPassModal]=useState(false);
  const [passwords,setPasswords]=useState({current:"",newp:"",confirm:""});
  const [passErr,setPassErr]=useState("");
  const pastor=user.role==="pastor"?PASTORS.find(p=>p.id===user.pastorId):null;
  const isSec=user.role==="secretary";
  const roleColor=isSec?C.purple:user.role==="pastor"?(pastor?.color||C.blue):C.blue;
  const roleBg=isSec?gradPurple:grad;
  const initials=user.name.split(" ").map(w=>w[0]).slice(0,2).join("").toUpperCase();
  const save=()=>{setUser(u=>({...u,...form}));setEditing(false);toast("Perfil actualizado");};
  const changePass=()=>{
    if(!passwords.current){setPassErr("Introduce tu contraseña actual.");return;}
    if(passwords.current!==user.password){setPassErr("Contraseña actual incorrecta.");return;}
    if(passwords.newp.length<6){setPassErr("Mínimo 6 caracteres.");return;}
    if(passwords.newp!==passwords.confirm){setPassErr("Las contraseñas no coinciden.");return;}
    setUser(u=>({...u,password:passwords.newp}));
    setPassModal(false);setPasswords({current:"",newp:"",confirm:""});
    toast("Contraseña actualizada");
  };
  return (
    <div style={{paddingBottom:84}}>
      <div style={{background:roleBg,padding:"52px 20px 32px",display:"flex",flexDirection:"column",alignItems:"center",position:"relative",overflow:"hidden"}}>
        <div style={{position:"absolute",top:-40,right:-40,width:140,height:140,borderRadius:"50%",background:"rgba(255,255,255,.07)"}}/>
        <div style={{width:76,height:76,borderRadius:22,background:"rgba(255,255,255,.2)",border:"2.5px solid rgba(255,255,255,.3)",display:"flex",alignItems:"center",justifyContent:"center",marginBottom:12,fontSize:isSec?32:user.role==="pastor"?32:20,fontWeight:900,color:C.white}}>
          {isSec?"📋":user.role==="pastor"?pastor?.icon:initials}
        </div>
        <h2 style={{color:C.white,margin:"0 0 4px",fontSize:20,fontWeight:900}}>{user.name}</h2>
        <span style={S.badge("rgba(255,255,255,.22)",C.white)}>
          {isSec?"📋 Secretario/a Pastoral":user.role==="pastor"?pastor?.role:"Miembro de la iglesia"}
        </span>
      </div>
      <div style={{padding:"16px"}}>
        {user.role==="pastor"&&pastor&&(
          <div style={{...S.card,background:pastor.colorSoft,border:`2px solid ${pastor.color}22`,display:"flex",alignItems:"center",gap:12,marginBottom:12}}>
            <div style={{width:48,height:48,borderRadius:13,background:`${pastor.color}22`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:26,flexShrink:0}}>{pastor.icon}</div>
            <div><p style={{margin:"0 0 3px",fontWeight:900,color:pastor.color,fontSize:15}}>{pastor.name} {pastor.surname}</p><span style={S.badge(pastor.color)}>{pastor.role}</span></div>
          </div>
        )}
        {isSec&&(
          <div style={{...S.card,background:C.purpleLight,border:`2px solid ${C.purple}22`,display:"flex",alignItems:"center",gap:12,marginBottom:12}}>
            <div style={{width:48,height:48,borderRadius:13,background:`${C.purple}18`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:26,flexShrink:0}}>📋</div>
            <div><p style={{margin:"0 0 3px",fontWeight:900,color:C.purple,fontSize:15}}>Secretario/a Pastoral</p><span style={S.badge(C.purple)}>Solo lectura</span></div>
          </div>
        )}
        <div style={S.card}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}>
            <p style={{margin:0,fontWeight:800,color:C.ink,fontSize:15}}>Información de Cuenta</p>
            <button onClick={()=>{setEditing(!editing);setForm({name:user.name,phone:user.phone||"",email:user.email,nie:user.nie||""});}} style={{background:editing?C.fog:`${roleColor}18`,color:editing?C.slate:roleColor,border:"none",borderRadius:9,padding:"6px 13px",cursor:"pointer",fontSize:12,fontWeight:700}}>{editing?"Cancelar":"✏️ Editar"}</button>
          </div>
          {editing?(
            <div style={{display:"flex",flexDirection:"column",gap:10}}>
              {[["name","Nombre completo"],["phone","Teléfono"],["email","Correo electrónico"],...(!isSec&&user.role!=="pastor"?[["nie","NIE (opcional)"]]:[])] .map(([k,lbl])=>(
                <div key={k}><label style={S.label}>{lbl}</label><input style={S.input} value={form[k]} onChange={e=>setForm(f=>({...f,[k]:e.target.value}))}/></div>
              ))}
              <button style={S.btn(isSec?C.purple:C.green)} onClick={save}>💾 Guardar cambios</button>
            </div>
          ):(
            <div>
              {[["📛 Nombre",user.name],["📧 Correo",user.email],["📞 Teléfono",user.phone||"—"],...(user.nie?[["🪪 NIE",user.nie]]:[]),["✅ Verificado","Sí"]].map(([k,v])=>(
                <div key={k} style={{display:"flex",justifyContent:"space-between",alignItems:"center",paddingBottom:9,marginBottom:9,borderBottom:`1px solid ${C.mist}`}}>
                  <span style={{fontSize:13,color:C.gray}}>{k}</span>
                  <span style={{fontSize:13,fontWeight:700,color:C.ink}}>{v}</span>
                </div>
              ))}
            </div>
          )}
        </div>
        <div style={S.card}>
          <p style={{margin:"0 0 12px",fontWeight:800,color:C.ink,fontSize:15}}>Seguridad</p>
          <button onClick={()=>setPassModal(true)} style={{...S.btnSm(C.fog,C.slate),width:"100%",textAlign:"left",padding:"12px 14px"}}>🔑 Cambiar contraseña</button>
        </div>
        <div style={{...S.card,background:gradSoft,border:`1px solid ${C.mist}`}}>
          <div style={{display:"flex",gap:10,alignItems:"center",marginBottom:6}}>
            <ChurchLogo size={36}/>
            <p style={{margin:0,fontWeight:900,color:C.navy,fontSize:14}}>Casa de Avivamiento Nueva Vida</p>
          </div>
          <p style={{margin:"0 0 2px",fontSize:12,color:C.slate}}>📍 Av. de Valencia 41, Zaragoza, España</p>
          <p style={{margin:0,fontSize:12,color:C.gray}}>📧 ig.nuevavida7@gmail.com</p>
        </div>
        <button onClick={onLogout} style={{...S.btn(C.redLight,C.red),marginTop:4}}>Cerrar Sesión</button>
      </div>
      <Modal open={passModal} onClose={()=>{setPassModal(false);setPassErr("");}}>
        <h3 style={{margin:"0 0 16px",fontSize:18,fontWeight:800,color:C.ink}}>Cambiar Contraseña</h3>
        <div style={{display:"flex",flexDirection:"column",gap:12}}>
          {[["current","Contraseña actual"],["newp","Nueva contraseña"],["confirm","Confirmar contraseña"]].map(([k,lbl])=>(
            <div key={k}><label style={S.label}>{lbl}</label><input style={S.input} type="password" placeholder="••••••••" value={passwords[k]} onChange={e=>setPasswords(p=>({...p,[k]:e.target.value}))}/></div>
          ))}
          {passErr&&<p style={S.err}>⚠️ {passErr}</p>}
          <button style={S.btn(roleColor)} onClick={changePass}>Actualizar contraseña</button>
        </div>
      </Modal>
    </div>
  );
}

/* ── ROOT APP ── */
export default function App() {
  const [splash,setSplash]           = useState(true);
  const [checkingSession,setChecking]= useState(true);
  const [screen,setScreen]           = useState("welcome");
  const [tab,setTab]                 = useState("home");
  const [currentUser,setCurrentUser] = useState(null);
  const [availability,setAvailability]=useState({});
  const [appointments,setAppointments]=useState([]);
  const [notifications,setNotifications]=useState([]);
  const [booking,setBooking]         = useState(false);
  const [editApt,setEditApt]         = useState(null);
  const [users,setUsers]             = useState([]);
  const {toasts,show:toast}          = useToast();

  // ── Restaurar sesión automáticamente al cargar/recargar la página ──
  useEffect(()=>{
    const unsub = listenAuthState((userData)=>{
      if (userData) {
        setCurrentUser(userData);
        setScreen("app");
      }
      setChecking(false);
    });
    return ()=>unsub();
  },[]);

  // ── Escuchar citas en tiempo real (todos los usuarios) ─────────────
  useEffect(()=>{
    const unsub = listenAppointments(list => setAppointments(list));
    return ()=>unsub();
  },[]);

  // ── Escuchar disponibilidad de TODOS los pastores en tiempo real ───
  useEffect(()=>{
    const unsubs = PASTORS.map(p =>
      listenAvailability(p.id, data =>
        setAvailability(prev => ({...prev, [p.id]: data}))
      )
    );
    return ()=>unsubs.forEach(u=>u());
  },[]);

  // ── Escuchar notificaciones en tiempo real ─────────────────────────
  useEffect(()=>{
    const unsub = listenNotifications(list => setNotifications(list));
    return ()=>unsub();
  },[]);

  if(splash || checkingSession) return <SplashScreen onDone={()=>setSplash(false)}/>;

  const login  = u => { setCurrentUser(u); setScreen("app"); setTab("home"); toast("¡Bienvenido/a, "+u.name.split(" ")[0]+"!"); };
  const logout = () => { logoutUser().catch(()=>{}); setCurrentUser(null); setScreen("welcome"); setBooking(false); setTab("home"); setEditApt(null); };

  const role   = currentUser?.role;
  const myUid  = role==="pastor" ? currentUser?.pastorId : currentUser?.id;

  const notifCount = notifications.filter(n=>
    !n.read && (n.targetId===myUid || (role==="secretary" && n.targetId==="secretary"))
  ).length;

  if(screen==="welcome")           return <><Toast toasts={toasts}/><WelcomeScreen onLogin={()=>setScreen("login")} onRegister={()=>setScreen("register")} onRegisterPastor={()=>setScreen("registerPastor")} onRegisterSecretary={()=>setScreen("registerSecretary")}/></>;
  if(screen==="login")             return <><Toast toasts={toasts}/><LoginScreen users={users} onSuccess={login} onBack={()=>setScreen("welcome")} toast={toast}/></>;
  if(screen==="register")          return <><Toast toasts={toasts}/><RegisterScreen users={users} setUsers={setUsers} onSuccess={login} onBack={()=>setScreen("welcome")} toast={toast}/></>;
  if(screen==="registerPastor")    return <><Toast toasts={toasts}/><PastorRegisterScreen users={users} setUsers={setUsers} onSuccess={login} onBack={()=>setScreen("welcome")} toast={toast}/></>;
  if(screen==="registerSecretary") return <><Toast toasts={toasts}/><SecretaryRegisterScreen users={users} setUsers={setUsers} onSuccess={login} onBack={()=>setScreen("welcome")} toast={toast}/></>;

  // ── Flujo de reserva/edición de cita ────────────────────────────────
  if((booking||editApt) && role==="member") return (
    <><Toast toasts={toasts}/>
    <BookingFlow
      user={currentUser}
      availability={availability}
      appointments={appointments}
      setAppointments={setAppointments}
      setNotifications={setNotifications}
      editApt={editApt}
      onDone={()=>{ setBooking(false); setEditApt(null); setTab("home"); }}
    /></>
  );

  const updateUser = u => {
    const r=typeof u==="function"?u(currentUser):u;
    setCurrentUser(r);
    setUsers(us=>us.map(x=>x.id===currentUser.id?r:x));
  };

  // ── Función para actualizar disponibilidad en Firestore ─────────────
  const handleSetAvailability = async (pastorId, dayKey, times) => {
    try {
      await setAvailabilityDay(pastorId, dayKey, times);
    } catch(e) {
      toast("Error al guardar disponibilidad","error");
    }
  };

  // ── Función para marcar notificación leída en Firestore ─────────────
  const handleMarkNotifRead = async (id) => {
    try { await markNotificationRead(id); } catch(e) { /* silencioso */ }
  };

  return (
    <div style={S.app}>
      <Toast toasts={toasts}/>
      <style>{`*{box-sizing:border-box}textarea,input{font-family:inherit}button:active{opacity:.78;transform:scale(.98)}::-webkit-scrollbar{width:0}`}</style>

      {role==="member"    && tab==="home"         && <HomeScreen user={currentUser} onBook={()=>setBooking(true)} appointments={appointments}/>}
      {role==="member"    && tab==="appointments" && <MyAppointments user={currentUser} appointments={appointments} setAppointments={setAppointments} availability={availability} setNotifications={setNotifications} toast={toast} onEdit={apt=>{setEditApt(apt);setBooking(false);}}/>}
      {role==="pastor"    && tab==="home"         && <PastorHome user={currentUser} appointments={appointments}/>}
      {role==="pastor"    && tab==="schedule"     && <PastorSchedule user={currentUser} availability={availability} setAvailability={handleSetAvailability} appointments={appointments} toast={toast}/>}
      {role==="secretary" && tab==="home"         && <SecretaryPanel user={currentUser} availability={availability} appointments={appointments} notifications={notifications} setNotifications={setNotifications}/>}
      {tab==="notifications" && <NotificationsScreen userId={myUid} userRole={role} notifications={notifications} onMarkRead={handleMarkNotifRead}/>}
      {tab==="profile"       && <ProfileScreen user={currentUser} setUser={updateUser} onLogout={logout} toast={toast}/>}
      <BottomNav tab={tab} setTab={setTab} role={role} notifCount={notifCount}/>
    </div>
  );
}
